<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Conway's Game of Life</title>
  <style>
    :root {
      --bg: #101322;
      --panel: #191d32;
      --panel-light: #242a48;
      --text: #f5f7ff;
      --muted: #9da7c9;
      --accent: #72f0bd;
      --accent-2: #8b7cff;
      --grid: rgba(164, 178, 235, 0.16);
    }

    * { box-sizing: border-box; }

    body {
      min-height: 100vh;
      margin: 0;
      display: grid;
      place-items: center;
      color: var(--text);
      background:
        radial-gradient(circle at 20% 10%, rgba(139,124,255,.18), transparent 30%),
        radial-gradient(circle at 90% 90%, rgba(114,240,189,.12), transparent 28%),
        var(--bg);
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    }

    .app {
      width: min(94vw, 650px);
      padding: 28px;
      text-align: center;
    }

    h1 {
      margin: 0 0 6px;
      font-size: clamp(2rem, 6vw, 3.3rem);
      letter-spacing: -0.06em;
      background: linear-gradient(100deg, var(--accent), #b1a7ff);
      -webkit-background-clip: text;
      background-clip: text;
      color: transparent;
    }

    .subtitle {
      margin: 0 0 22px;
      color: var(--muted);
      font-size: .95rem;
    }

    .board-wrap {
      display: inline-block;
      padding: 12px;
      border-radius: 22px;
      background: linear-gradient(145deg, #292e4c, #15182a);
      box-shadow: 0 20px 60px rgba(0,0,0,.42), 0 0 0 1px rgba(255,255,255,.06);
    }

    #life {
      display: block;
      width: 520px;
      height: 520px;
      max-width: none;
      border-radius: 12px;
      background: #0b0e1a;
      cursor: crosshair;
      touch-action: none;
    }

    .controls {
      display: flex;
      justify-content: center;
      flex-wrap: wrap;
      gap: 10px;
      margin-top: 20px;
    }

    button {
      border: 0;
      border-radius: 999px;
      padding: 11px 18px;
      color: var(--text);
      background: var(--panel);
      box-shadow: inset 0 0 0 1px rgba(255,255,255,.1), 0 5px 14px rgba(0,0,0,.2);
      font: inherit;
      font-weight: 700;
      cursor: pointer;
      transition: transform .15s ease, background .15s ease, box-shadow .15s ease;
    }

    button:hover {
      transform: translateY(-2px);
      background: var(--panel-light);
      box-shadow: inset 0 0 0 1px rgba(255,255,255,.18), 0 8px 18px rgba(0,0,0,.28);
    }

    button:active { transform: translateY(1px) scale(.98); }

    #play {
      color: #101322;
      background: var(--accent);
    }

    #play:hover { background: #91f8cb; }

    .hint {
      margin: 16px 0 0;
      color: var(--muted);
      font-size: .84rem;
    }

    @media (max-width: 590px) {
      .app { padding: 16px 8px; }
      .board-wrap { padding: 8px; }
      #life {
        width: min(520px, calc(100vw - 32px));
        height: min(520px, calc(100vw - 32px));
      }
    }
  </style>
</head>
<body>
  <main class="app">
    <h1>Life, but make it ✨</h1>
    <p class="subtitle">Tiny rules. Infinite little universes.</p>

    <div class="board-wrap">
      <canvas id="life" aria-label="Conway's Game of Life grid"></canvas>
    </div>

    <div class="controls">
      <button id="step" type="button">⏭ Step</button>
      <button id="play" type="button">▶ Play</button>
      <button id="random" type="button">🎲 Randomize</button>
      <button id="clear" type="button">🧹 Clear</button>
    </div>
    <p class="hint">Click or drag to paint cells · B3/S23 rules</p>
  </main>

  <script>
    (() => {
      const canvas = document.getElementById("life");
      const ctx = canvas.getContext("2d");
      const w = 48;
      const h = 48;
      const size = 520;
      let cells = new Uint8Array(w * h);
      let running = false;
      let timer = null;
      let lastCell = -1;
      let paintValue = 1;

      const index = (x, y) => y * w + x;

      function resizeCanvas() {
        const dpr = Math.max(1, window.devicePixelRatio || 1);
        canvas.width = size * dpr;
        canvas.height = size * dpr;
        ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
        draw();
      }

      function draw() {
        const cellSize = size / w;
        ctx.clearRect(0, 0, size, size);
        ctx.fillStyle = "#0b0e1a";
        ctx.fillRect(0, 0, size, size);

        ctx.strokeStyle = getComputedStyle(document.documentElement)
          .getPropertyValue("--grid").trim();
        ctx.lineWidth = 0.7;
        ctx.beginPath();
        for (let x = 0; x <= w; x++) {
          const p = Math.round(x * cellSize) + 0.5;
          ctx.moveTo(p, 0);
          ctx.lineTo(p, size);
        }
        for (let y = 0; y <= h; y++) {
          const p = Math.round(y * cellSize) + 0.5;
          ctx.moveTo(0, p);
          ctx.lineTo(size, p);
        }
        ctx.stroke();

        ctx.fillStyle = "#72f0bd";
        for (let y = 0; y < h; y++) {
          for (let x = 0; x < w; x++) {
            if (cells[index(x, y)]) {
              const pad = Math.max(1.2, cellSize * 0.13);
              ctx.fillRect(
                x * cellSize + pad,
                y * cellSize + pad,
                cellSize - pad * 2,
                cellSize - pad * 2
              );
            }
          }
        }
      }

      function get(x, y) {
        x = Math.floor(x);
        y = Math.floor(y);
        if (x < 0 || x >= w || y < 0 || y >= h) return 0;
        return cells[index(x, y)];
      }

      function set(x, y, value) {
        x = Math.floor(x);
        y = Math.floor(y);
        if (x < 0 || x >= w || y < 0 || y >= h) return;
        cells[index(x, y)] = value ? 1 : 0;
        draw();
      }

      function step() {
        const next = new Uint8Array(w * h);
        for (let y = 0; y < h; y++) {
          for (let x = 0; x < w; x++) {
            let neighbours = 0;
            for (let dy = -1; dy <= 1; dy++) {
              for (let dx = -1; dx <= 1; dx++) {
                if (dx !== 0 || dy !== 0) neighbours += get(x + dx, y + dy);
              }
            }
            const alive = cells[index(x, y)] === 1;
            next[index(x, y)] = alive
              ? (neighbours === 2 || neighbours === 3 ? 1 : 0)
              : (neighbours === 3 ? 1 : 0);
          }
        }
        cells = next;
        draw();
      }

      function clear() {
        cells.fill(0);
        draw();
      }

      function randomize() {
        for (let i = 0; i < cells.length; i++) {
          cells[i] = Math.random() < 0.28 ? 1 : 0;
        }
        draw();
      }

      function cellFromEvent(event) {
        const rect = canvas.getBoundingClientRect();
        const x = Math.floor((event.clientX - rect.left) / rect.width * w);
        const y = Math.floor((event.clientY - rect.top) / rect.height * h);
        return { x, y };
      }

      canvas.addEventListener("pointerdown", (event) => {
        event.preventDefault();
        canvas.setPointerCapture(event.pointerId);
        const { x, y } = cellFromEvent(event);
        if (x < 0 || x >= w || y < 0 || y >= h) return;
        paintValue = get(x, y) ? 0 : 1;
        lastCell = index(x, y);
        set(x, y, paintValue);
      });

      canvas.addEventListener("pointermove", (event) => {
        if (!canvas.hasPointerCapture(event.pointerId)) return;
        const { x, y } = cellFromEvent(event);
        if (x < 0 || x >= w || y < 0 || y >= h) return;
        const i = index(x, y);
        if (i !== lastCell) {
          lastCell = i;
          set(x, y, paintValue);
        }
      });

      canvas.addEventListener("pointerup", () => { lastCell = -1; });
      canvas.addEventListener("pointercancel", () => { lastCell = -1; });

      document.getElementById("step").addEventListener("click", step);
      document.getElementById("clear").addEventListener("click", clear);
      document.getElementById("random").addEventListener("click", randomize);

      document.getElementById("play").addEventListener("click", () => {
        running = !running;
        const button = document.getElementById("play");
        button.textContent = running ? "⏸ Pause" : "▶ Play";
        if (running) {
          timer = setInterval(step, 120);
        } else {
          clearInterval(timer);
          timer = null;
        }
      });

      window.life = { w, h, get, set, step, clear };
      resizeCanvas();
      window.addEventListener("resize", resizeCanvas);
    })();
  </script>
</body>
</html>
